// Input: receives finalized video + metadata from upstream workflows
// This workflow is CALLED, not triggered independently
const input = $input.first().json;
return [{ json: {
  video_path: input.video_path || '',
  title: input.title || 'Untitled',
  description: input.description || '',
  tags: input.tags || [],
  hashtags: input.hashtags || [],
  chapters: input.chapters || '',
  thumbnail_path: input.thumbnail_path || '',
  platforms: input.platforms || ['youtube'],
  aspect_variants: input.aspect_variants || {},
  client: input.client || 'PopTech Studio',
  production_order_id: input.production_order_id || '',
  visibility: input.visibility || 'unlisted',
  scheduled_time: input.scheduled_time || null,
}}];

// FFmpeg: Generate aspect ratio variants if not already provided
const input = $json;
const variants = input.aspect_variants;
if (!variants['16:9'] && !variants['9:16']) {
  // Generate all 3 from the source video
  return [{ json: { ...input, encode_commands: [
    { aspect: '16:9', res: '1920x1080', platform: 'youtube', command: `ffmpeg -y -i ${input.video_path} -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2:black" -c:v libx264 -crf 18 -c:a aac -b:a 192k output_16x9.mp4` },
    { aspect: '9:16', res: '1080x1920', platform: 'reels_tiktok_shorts', command: `ffmpeg -y -i ${input.video_path} -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" -c:v libx264 -crf 18 -c:a aac -b:a 192k output_9x16.mp4` },
    { aspect: '1:1', res: '1080x1080', platform: 'facebook_feed', command: `ffmpeg -y -i ${input.video_path} -vf "scale=1080:1080:force_original_aspect_ratio=decrease,pad=1080:1080:(ow-iw)/2:(oh-ih)/2:black" -c:v libx264 -crf 18 -c:a aac -b:a 128k output_1x1.mp4` },
  ]}}];
}
return [{ json: input }];

// Platform-specific metadata generation
const input = $json;
const metadata = {};

// YouTube: full description, tags, chapters
metadata.youtube = {
  title: input.title,
  description: `${input.description}\n\n${input.chapters || ''}\n\n#${(input.tags || []).join(' #')}`,
  tags: input.tags,
  category: 'Film & Animation',
  visibility: input.visibility || 'unlisted',
  file: 'output_16x9.mp4',
};

// Instagram Reels: caption with hashtags
metadata.instagram_reels = {
  caption: `${input.description.slice(0, 150)}\n\n${(input.hashtags || []).map(h => `#${h}`).join(' ')}`,
  file: 'output_9x16.mp4',
};

// TikTok: caption with hashtags (different format)
metadata.tiktok = {
  caption: `${input.title} ${(input.hashtags || []).map(h => `#${h}`).join(' ')}`,
  file: 'output_9x16.mp4',
};

// YouTube Shorts: same as YouTube but 9:16
metadata.youtube_shorts = {
  title: `${input.title} #shorts`,
  description: input.description,
  tags: [...(input.tags || []), 'shorts'],
  file: 'output_9x16.mp4',
};

// LinkedIn: professional, no hashtags
metadata.linkedin = {
  title: input.title,
  description: input.description,
  file: 'output_16x9.mp4',
};

// Facebook: 1:1 with description
metadata.facebook = {
  caption: input.description,
  file: 'output_1x1.mp4',
};

return [{ json: { ...input, platform_metadata: metadata }}];

// Platform dispatch — route to Blotato MCP or direct API
const platform = $json;
const meta = $('Platform Metadata Generator').first().json.platform_metadata;
const platformData = meta[platform] || {};

return [{ json: {
  platform: platform,
  file: platformData.file || 'output_16x9.mp4',
  metadata: platformData,
  publish_method: 'blotato_mcp',
  publish_status: 'stub_queued',
  timestamp: new Date().toISOString(),
}}];
// STUB: Blotato MCP or direct API upload. YouTube uses unlisted-first review gate.

// Aggregate publish results
const results = $input.all().map(i => i.json);
const successful = results.filter(r => r.publish_status !== 'failed').length;
return [{ json: {
  total_platforms: results.length,
  successful: successful,
  failed: results.length - successful,
  results: results,
  timestamp: new Date().toISOString(),
}}];

// Log to MySQL publish_log table
const summary = $json;
return [{ json: {
  log_entry: {
    production_order_id: $('Receive Publish Request').first().json.production_order_id,
    client: $('Receive Publish Request').first().json.client,
    platforms_total: summary.total_platforms,
    platforms_success: summary.successful,
    platforms_failed: summary.failed,
    details: summary.results,
    timestamp: summary.timestamp,
  },
  publish_complete: true,
}}];
// STUB: MySQL INSERT into publish_log table on VPS

// Notification
const input = $('Receive Publish Request').first().json;
const summary = $('Aggregate Publish Results').first().json;
return [{ json: {
  text: `*Video Published*\nProject: ${input.title}\nClient: ${input.client}\nPlatforms: ${summary.successful}/${summary.total_platforms} successful\nVisibility: ${input.visibility}`,
}}];
